+import Yoga, {type Node as YogaNode} from 'yoga-layout';
+import {type DOMElement, type DOMNode} from './dom.js';
+
+type Track =
+	| {type: 'fixed'; value: number}
+	| {type: 'fr'; value: number; min: number}
+	| {type: 'auto'};
+
+type Placement = {start: number; end: number};
+
+const splitTracks = (value: string): string[] => {
+	const tracks: string[] = [];
+	let depth = 0;
+	let token = '';
+
+	for (const character of value.trim()) {
+		if (character === '(') depth++;
+		if (character === ')') depth--;
+		if (/\\s/.test(character) && depth === 0) {
+			if (token) tracks.push(token);
+			token = '';
+		} else {
+			token += character;
+		}
+	}
+
+	if (token) tracks.push(token);
+	return tracks;
+};
+
+const parseTrack = (value: string): Track => {
+	if (value === 'auto') return {type: 'auto'};
+
+	const fraction = /^(\\d*\\.?\\d+)fr$/.exec(value);
+	if (fraction) return {type: 'fr', value: Number(fraction[1]), min: 0};
+
+	const minmax = /^minmax\\((\\d*\\.?\\d+)\\s*,\\s*(\\d*\\.?\\d+|\\d*\\.?\\d+fr)\\)$/.exec(value);
+	if (minmax) {
+		const min = Number(minmax[1]);
+		const max = minmax[2];
+		const maxFraction = /^(\\d*\\.?\\d+)fr$/.exec(max);
+		return maxFraction
+			? {type: 'fr', value: Number(maxFraction[1]), min}
+			: {type: 'fixed', value: Number(max)};
+	}
+
+	const fixed = Number(value);
+	if (Number.isFinite(fixed)) return {type: 'fixed', value: fixed};
+
+	throw new Error(`Invalid grid track size: ${value}`);
+};
+
+const parseTracks = (value: string | undefined, fallback: number): Track[] =>
+	value ? splitTracks(value).map(parseTrack) : Array.from({length: fallback}, () => ({type: 'auto'}));
+
+const parsePlacement = (value: number | string | undefined): Placement | undefined => {
+	if (typeof value === 'number') return {start: value - 1, end: value};
+	if (!value) return;
+	const match = /^(\\d+)\\s*\\/\\s*(\\d+)$/.exec(value);
+	if (!match) throw new Error(`Invalid grid placement: ${value}`);
+	return {start: Number(match[1]) - 1, end: Number(match[2]) - 1};
+};
+
+const getGap = (node: DOMElement, axis: 'column' | 'row'): number =>
+	axis === 'column'
+		? (node.style.columnGap ?? node.style.gap ?? 0)
+		: (node.style.rowGap ?? node.style.gap ?? 0);
+
+const resolveTracks = (
+	tracks: Track[],
+	available: number,
+	gap: number,
+	autoSizes: number[],
+): number[] => {
+	const base = tracks.reduce((total, track, index) =>
+		total + (track.type === 'fixed' ? track.value : track.type === 'auto' ? (autoSizes[index] ?? 0) : track.min), 0);
+	const free = Math.max(0, available - gap * Math.max(0, tracks.length - 1) - base);
+	const fractionTotal = tracks.reduce((total, track) => total + (track.type === 'fr' ? track.value : 0), 0);
+	return tracks.map((track, index) => {
+		if (track.type === 'fixed') return track.value;
+		if (track.type === 'auto') return autoSizes[index] ?? 0;
+		return track.min + (fractionTotal > 0 ? free * track.value / fractionTotal : 0);
+	});
+};
+
+const offsets = (tracks: number[], gap: number): number[] => {
+	let offset = 0;
+	return tracks.map(track => {
+		const result = offset;
+		offset += track + gap;
+		return result;
+	});
+};
+
+const gridChildren = (node: DOMElement): DOMElement[] =>
+	node.childNodes.filter((child): child is DOMElement => child.nodeName !== '#text' && Boolean(child.yogaNode));
+
+const prepareGridNodes = (node: DOMNode): void => {
+	if (node.nodeName === '#text') return;
+	if (node.style.display === 'grid') {
+		for (const child of gridChildren(node)) {
+			child.yogaNode!.setPositionType(Yoga.POSITION_TYPE_ABSOLUTE);
+		}
+	}
+
+	for (const child of node.childNodes) prepareGridNodes(child);
+};
+
+const layoutGrid = (node: DOMElement): void => {
+	const yogaNode = node.yogaNode!;
+	const children = gridChildren(node);
+	const columns = parseTracks(node.style.gridTemplateColumns, 1);
+	const columnGap = getGap(node, 'column');
+	const rowGap = getGap(node, 'row');
+	const placements = children.map(child => ({
+		child,
+		column: parsePlacement(child.style.gridColumn),
+		row: parsePlacement(child.style.gridRow),
+	}));
+
+	let cursor = 0;
+	for (const placement of placements) {
+		placement.column ??= {start: cursor % columns.length, end: cursor % columns.length + 1};
+		placement.row ??= {start: Math.floor(cursor / columns.length), end: Math.floor(cursor / columns.length) + 1};
+		cursor++;
+	}
+
+	const rowCount = Math.max(1, ...placements.map(placement => placement.row!.end));
+	const rows = parseTracks(node.style.gridTemplateRows, rowCount);
+	while (rows.length < rowCount) rows.push({type: 'auto'});
+
+	const contentWidth = yogaNode.getComputedWidth() - yogaNode.getComputedPadding(Yoga.EDGE_LEFT) - yogaNode.getComputedPadding(Yoga.EDGE_RIGHT) - yogaNode.getComputedBorder(Yoga.EDGE_LEFT) - yogaNode.getComputedBorder(Yoga.EDGE_RIGHT);
+	const columnAutoSizes = columns.map(() => 0);
+	for (const placement of placements) {
+		if (placement.column!.end - placement.column!.start === 1) {
+			const index = placement.column!.start;
+			if (columns[index]?.type === 'auto') columnAutoSizes[index] = Math.max(columnAutoSizes[index], placement.child.yogaNode!.getComputedWidth());
+		}
+	}
+	const columnSizes = resolveTracks(columns, contentWidth, columnGap, columnAutoSizes);
+	const columnOffsets = offsets(columnSizes, columnGap);
+
+	for (const placement of placements) {
+		const {child, column} = placement;
+		const width = columnOffsets[column!.end - 1] + columnSizes[column!.end - 1] - columnOffsets[column!.start];
+		child.yogaNode!.setWidth(width);
+		child.yogaNode!.setPosition(Yoga.EDGE_LEFT, columnOffsets[column!.start]);
+	}
+
+	// Yoga now measures text at its grid-assigned width. The next pass converts
+	// those measurements into automatic row sizes.
+	const rowAutoSizes = rows.map(() => 0);
+	for (const placement of placements) {
+		if (placement.row!.end - placement.row!.start === 1) {
+			const index = placement.row!.start;
+			if (rows[index]?.type === 'auto') rowAutoSizes[index] = Math.max(rowAutoSizes[index], placement.child.yogaNode!.getComputedHeight());
+		}
+	}
+	const contentHeight = yogaNode.getComputedHeight() - yogaNode.getComputedPadding(Yoga.EDGE_TOP) - yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) - yogaNode.getComputedBorder(Yoga.EDGE_TOP) - yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM);
+	const rowSizes = resolveTracks(rows, contentHeight, rowGap, rowAutoSizes);
+	const rowOffsets = offsets(rowSizes, rowGap);
+
+	for (const placement of placements) {
+		const {child, column, row} = placement;
+		const width = columnOffsets[column!.end - 1] + columnSizes[column!.end - 1] - columnOffsets[column!.start];
+		const height = rowOffsets[row!.end - 1] + rowSizes[row!.end - 1] - rowOffsets[row!.start];
+		child.yogaNode!.setWidth(width);
+		child.yogaNode!.setHeight(height);
+		child.yogaNode!.setPosition(Yoga.EDGE_LEFT, columnOffsets[column!.start]);
+		child.yogaNode!.setPosition(Yoga.EDGE_TOP, rowOffsets[row!.start]);
+	}
+
+	if (!('height' in node.style)) {
+		yogaNode.setHeight(rowSizes.reduce((total, size) => total + size, 0) + rowGap * Math.max(0, rowSizes.length - 1) + yogaNode.getComputedPadding(Yoga.EDGE_TOP) + yogaNode.getComputedPadding(Yoga.EDGE_BOTTOM) + yogaNode.getComputedBorder(Yoga.EDGE_TOP) + yogaNode.getComputedBorder(Yoga.EDGE_BOTTOM));
+	}
+};
+
+const visitGrids = (node: DOMNode): void => {
+	if (node.nodeName === '#text') return;
+	if (node.style.display === 'grid') layoutGrid(node);
+	for (const child of node.childNodes) visitGrids(child);
+};
+
+export const calculateLayout = (root: DOMElement, width?: number): void => {
+	prepareGridNodes(root);
+	if (width !== undefined) root.yogaNode!.setWidth(width);
+	root.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	// Two passes let automatic tracks use text measurements at their assigned width.
+	for (let index = 0; index < 2; index++) {
+		visitGrids(root);
+		root.yogaNode!.calculateLayout(undefined, undefined, Yoga.DIRECTION_LTR);
+	}
+};
